#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Structure for a queue node
typedef struct QueueNode {
    int vertex;
    struct QueueNode* next;
} QueueNode;

// Structure for a graph
typedef struct Graph {
    int numVertices;
    int* visited;
    int** adjLists;
} Graph;

// Function to create a graph
Graph* createGraph(int vertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = vertices;
    graph->visited = (int*) malloc(vertices * sizeof(int));
    graph->adjLists = (int**) malloc(vertices * sizeof(int*));
    for (int i = 0; i < vertices; i++) {
        graph->adjLists[i] = (int*) malloc(2 * sizeof(int));
        graph->adjLists[i][0] = -1;
        graph->adjLists[i][1] = -1;
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    int* newNode = (int*) malloc(2 * sizeof(int));
    newNode[0] = dest;
    newNode[1] = graph->adjLists[src][0];
    graph->adjLists[src][0] = newNode - graph->adjLists[src];
}

// Function to detect a cycle using BFS
bool detectCycle(Graph* graph, int vertex) {
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
    }
    QueueNode* queue = (QueueNode*) malloc(sizeof(QueueNode));
    queue->vertex = vertex;
    queue->next = NULL;
    visited[vertex] = 1;
    while (queue != NULL) {
        int currentVertex = queue->vertex;
        QueueNode* temp = queue;
        queue = queue->next;
        free(temp);
        for (int i = 0; i < graph->numVertices; i++) {
            if (graph->adjLists[currentVertex][i] != -1 && !visited[graph->adjLists[currentVertex][i]]) {
                QueueNode* newNode = (QueueNode*) malloc(sizeof(QueueNode));
                newNode->vertex = graph->adjLists[currentVertex][i];
                newNode->next = queue;
                queue = newNode;
                visited[graph->adjLists[currentVertex][i]] = 1;
            } else if (graph->adjLists[currentVertex][i] != -1 && visited[graph->adjLists[currentVertex][i]]) {
                return true;
            }
        }
    }
    return false;
}

int main() {
    int vertices, edges;
    scanf("%d %d", &vertices, &edges);
    Graph* graph = createGraph(vertices);
    for (int i = 0; i < edges; i++) {
        int src, dest;
        scanf("%d %d", &src, &dest);
        addEdge(graph, src, dest);
        addEdge(graph, dest, src);
    }
    bool cycle = false;
    for (int i = 0; i < vertices; i++) {
        if (!graph->visited[i]) {
            if (detectCycle(graph, i)) {
                cycle = true;
                break;
            }
        }
    }
    if (cycle) {
        printf("1\n");
    } else {
        printf("0\n");
    }
    return 0;
}

