from collections import defaultdict, deque

class Solution:
    def isCycle(self, V, adj):
        visited = [False] * V
        for i in range(V):
            if not visited[i]:
                if self.detect(i, adj, visited):
                    return True
        return False

    def detect(self, src, adj, visited):
        visited[src] = True
        queue = deque([(src, -1)])
        while queue:
            node, parent = queue.popleft()
            for adjacentNode in adj[node]:
                if not visited[adjacentNode]:
                    visited[adjacentNode] = True
                    queue.append((adjacentNode, node))
                elif parent != adjacentNode:
                    return True
        return False

